    outcome = []

    # Process each pair of scores and predictions
    for index in range(len(game)):
        actual_score = game[index]
        predicted_score = guess[index]

        # Calculate absolute difference between actual and predicted
        if actual_score == predicted_score:
            outcome.append(0)
        else:
            absolute_gap = abs(actual_score - predicted_score)
            outcome.append(absolute_gap)

    return outcome

def reverse_delete(s, c):
    # Build new string by keeping only allowed characters
    outcome = ""
    banned_set = set(c)

    for each_char in s:
        if each_char not in banned_set:
            outcome += each_char

    # Palindrome check by comparing with its opposite
    is_palindrome = outcome == outcome[::-1]

    return (outcome, is_palindrome)

def encode_shift(s: str):
    """
    returns encoded string by shifting every character by 5 in the alphabet.
    """
    return "".join([chr(((ord(ch) + 5 - ord("a")) % 26) + ord("a")) for ch in s])


def decode_shift(s: str):
    """
    takes as input string encoded with encode_shift function. Returns decoded string.
    """
    # Apply opposite shift: subtract 5 positions in alphabet
    return "".join([chr(((ord(each_char) - 5 - ord("a")) % 26) + ord("a")) for each_char in s])

