        if segment:  # Only process non-empty segments
            sorted_chars = ''.join(sorted(segment))
            ordered_segments.append(sorted_chars)
        else:
            ordered_segments.append(segment)

    # Join back with spaces
    return ' '.join(ordered_segments)

