def correct_bracketing(brackets: str):
    """ brackets is a string of "<" and ">".
    return True if every opening bracket has a corresponding closing bracket.
    """
    open_stack = 0

    # Process each bracket in sequence
    for bracket in brackets:
        if bracket == "<":
            open_stack += 1
        elif bracket == ">":
            open_stack -= 1
            # If negative, we have an opening bracket without prior open
            if open_stack < 0:
                return False

    # All opening brackets should have pairs
    return open_stack == 0

