    if n == 0:
        return [1]

    # Initialize sequence starting with base values
    sequence = [0] * (n + 1)
    sequence[0] = 1
    sequence[1] = 3

    # Process even positions using simple arithmetic
    for pos in range(2, n + 1):
        if pos % 2 == 0:
            sequence[pos] = 1 + pos // 2

    # Process odd positions using recurrence relationship
    for pos in range(3, n + 1, 2):
        sequence[pos] = sequence[pos - 1] + sequence[pos - 2] + sequence[pos + 1]

    return sequence

