        if part.isdigit():
            number = int(part)
            if i + 1 < len(parts) and parts[i + 1].startswith('apple'):
                apple_count = number
            elif i + 1 < len(parts) and parts[i + 1].startswith('orange'):
                orange_count = number

    # Subtract apple and orange counts from total
    mango_count = n - apple_count - orange_count
    return mango_count

