def fix_spaces(text):
    """
    Given a string text, replace all spaces in it with underscores, 
    and if a string has more than 2 consecutive spaces, 
    then replace all consecutive spaces with - 
    """
    output = ""
    space_counter = 0

    for character in text:
        if character == ' ':
            space_counter += 1
        else:
            # Process accumulated spaces before adding the character
            if space_counter > 0:
                if space_counter > 2:
                    output += '-'
                else:
                    output += '_' * space_counter
                space_counter = 0
            output += character

    # Handle any spaces at the end of the string
    if space_counter > 0:
        if space_counter > 2:
            output += '-'
        else:
            output += '_' * space_counter

    return output
```

