def bf(planet1, planet2):
    # Solar system planets ordered by proximity to Sun
    solar_bodies = ["Mercury", "Venus", "Earth", "Mars", "Jupiter", "Saturn", "Uranus", "Neptune"]

    # Initial checks for planet names
    if planet1 not in solar_bodies or planet2 not in solar_bodies:
        return ()

    # Obtain positions in solar system
    initial_spot = solar_bodies.index(planet1)
    ending_spot = solar_bodies.index(planet2)

    # Ensure initial position is before ending position
    if initial_spot > ending_spot:
        initial_spot, ending_spot = ending_spot, initial_spot

    # Obtain planets between positions and skip boundary planets
    inner_planets = solar_bodies[initial_spot + 1:ending_spot]

    return tuple(inner_planets)

