def is_nested(string):
    open_brackets = []
    nested_pairs = []

    # Process each bracket in sequence
    for index, bracket in enumerate(string):
        if bracket == '[':
            open_brackets.append(index)
        elif bracket == ']' and open_brackets:
            opening_pos = open_brackets.pop()
            nested_pairs.append((opening_pos, index))

    # Check if any pair is nested inside another pair
    for i in range(len(nested_pairs)):
        for j in range(len(nested_pairs)):
            if i != j:
                outer_start, outer_end = nested_pairs[i]
                inner_start, inner_end = nested_pairs[j]
                # Inner pair is nested if both positions are between outer positions
                if outer_start < inner_start and inner_end < outer_end:
                    return True

    return False
```

