def sort_even(input_list: list):
    """Sort values at even positions while keeping odd positions unchanged."""
    if not input_list:
        return []

    # Extract values at even positions
    even_position_values = []
    for position in range(len(input_list)):
        if position % 2 == 0:
            even_position_values.append(input_list[position])

    # Sort the even position values
    even_position_values.sort()

    # Build output list by inserting sorted even values back
    output_sequence = []
    even_index = 0

    for position in range(len(input_list)):
        if position % 2 == 0:
            # Insert next sorted even value
            output_sequence.append(even_position_values[even_index])
            even_index += 1
        else:
            # Keep original value at odd positions
            output_sequence.append(input_list[position])

    return output_sequence

from typing import List


def remove_duplicates(numbers: List[int]) -> List[int]:
    """ From a list of integers, remove all elements that occur more than once.
    Keep order of elements left the same as in the input.
    >>> remove_duplicates([1, 2, 3, 2, 4])
    [1, 3, 4]
    """
    # Count occurrences of each number
    occurrence_counts = {}

    # Build occurrence count map
    for num in numbers:
        if num in occurrence_counts:
            occurrence_counts[num] += 1
        else:
            occurrence_counts[num] = 1

    # Keep only numbers that appear exactly once
    unique_items = []
    for num in numbers:
        if occurrence_counts[num] == 1:
            unique_items.append(num)

    return unique_items

