def words_in_sentence(sentence):
    def is_prime_number(number):
        if number < 2:
            return False
        for i in range(2, int(number ** 0.5) + 1):
            if number % i == 0:
                return False
        return True

    # Split sentence into individual pieces
    separate_pieces = sentence.split()
    prime_based_pieces = []

    for piece in separate_pieces:
        piece_size = len(piece)
        if is_prime_number(piece_size):
            prime_based_pieces.append(piece)

    # Join pieces back into single output
    return " ".join(prime_based_pieces)
